<?php
require_once __DIR__.'/functions.php';
$posts=db()->query("SELECT p.id,p.titulo,p.slug,p.contenido,p.imagen,p.author_name,p.fecha,m.avatar,m.profile_slug,m.profile_public,COALESCE(v.total,0) views,COALESCE(r.likes,0) likes,COALESCE(r.dislikes,0) dislikes,COALESCE(s.total,0) shares,COALESCE(c.total,0) comments FROM posts p LEFT JOIN members m ON m.id=p.member_author_id LEFT JOIN (SELECT post_id,COUNT(*) total FROM post_views GROUP BY post_id) v ON v.post_id=p.id LEFT JOIN (SELECT post_id,SUM(reaction=1) likes,SUM(reaction=-1) dislikes FROM (SELECT post_id,reaction FROM post_reactions UNION ALL SELECT post_id,reaction FROM post_staff_reactions) all_reactions GROUP BY post_id) r ON r.post_id=p.id LEFT JOIN (SELECT post_id,COUNT(*) total FROM post_shares GROUP BY post_id) s ON s.post_id=p.id LEFT JOIN (SELECT post_id,COUNT(*) total FROM comments WHERE aprobado=1 GROUP BY post_id) c ON c.post_id=p.id WHERE p.post_type='community' AND p.status='published' ORDER BY p.fecha DESC")->fetchAll();
render_header('Comunidad',['canonical'=>'/community.php']);?><header class="hero"><h1>Comunidad</h1><p>Publicaciones creadas por los lectores.</p><?php if(is_member_verified()):?><a class="button" href="/community-write.php">Crear publicación</a><?php endif;?></header><div class="grid"><?php foreach($posts as $post):?><article class="card"><?php if($post['imagen']):?><img src="/uploads/<?=e($post['imagen'])?>" alt="<?=e($post['titulo'])?>"><?php endif;?><div class="pad"><div class="author-meta"><?php $profileUrl=public_profile_url($post);if($profileUrl):?><a class="author-profile-link" href="<?=e($profileUrl)?>"><?php endif;?><?php if($post['avatar']):?><img class="avatar avatar-sm" src="/uploads/<?=e($post['avatar'])?>" alt=""><?php endif;?><small><?=e(format_date($post['fecha']))?> · <?=e($post['author_name'])?></small><?php if($profileUrl):?></a><?php endif;?></div><h2><a href="<?=e(post_url($post))?>"><?=e($post['titulo'])?></a></h2><p><?=e(mb_strimwidth(strip_tags($post['contenido']),0,150,'…'))?></p><a class="more" href="<?=e(post_url($post))?>">Abrir conversación →</a><div class="card-stats"><span>👁 <?=(int)$post['views']?></span><span>👍 <?=(int)$post['likes']?></span><span>👎 <?=(int)$post['dislikes']?></span><span>💬 <?=(int)$post['comments']?></span><span>↗ <?=(int)$post['shares']?></span></div></div></article><?php endforeach;?><?php if(!$posts):?><p class="empty">Todavía no hay publicaciones de la comunidad.</p><?php endif;?></div><?php render_footer();
